import{_ as t,o,c as d,ag as a}from"./chunks/framework.HG0H2VLS.js";const h=JSON.parse('{"title":"AssistantPopover — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/patterns/AssistantPopover/AssistantPopover.figma-notes.md","filePath":"public/demos/src/cc/patterns/AssistantPopover/AssistantPopover.figma-notes.md"}'),c={name:"public/demos/src/cc/patterns/AssistantPopover/AssistantPopover.figma-notes.md"};function r(s,e,i,n,l,p){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="assistantpopover-—-figma-notes" tabindex="-1">AssistantPopover — Figma Notes <a class="header-anchor" href="#assistantpopover-—-figma-notes" aria-label="Permalink to &quot;AssistantPopover — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li><strong>File key:</strong> <code>ETKqleZdpertwFEo40YB5n</code> (Affino CC Hybrid – Design System)</li><li><strong>Component (Tier=Pattern, Type=Pop Over):</strong> <code>4218:5304</code> (320×277)</li><li>Children: header <code>4218:5305</code> (ChatHeader instance, 320×56), body frame <code>4218:5306</code> (intro <code>4218:5307</code> with hidden Title + visible Subtext <code>4218:5309</code>), Launch button instance <code>4218:5337</code> (288×40).</li></ul><h2 id="architecture-decision" tabindex="-1">Architecture decision <a class="header-anchor" href="#architecture-decision" aria-label="Permalink to &quot;Architecture decision&quot;">​</a></h2><p>Figma models this as the <code>AiAssistant</code> component&#39;s <code>Type=Pop Over</code> variant, but per user direction it is built as a <strong>standalone pattern</strong> (<code>src/cc/patterns/AssistantPopover/</code>), <strong>not</strong> part of the AiAssistant template. The header is <strong>self-contained</strong> (own BEM classes) — it resembles the CC ChatHeader treatment but is not the ChatHeader component (different slots: AI badge + close, no sidebar toggle / agent selector). Decisions taken 2026-06-03.</p><h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Single variant — <code>Type=Pop Over</code>. No size/state axes in Figma. Scoped to this one variant by user instruction (behaviour to be specced later).</p><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Pop Over root (<code>4218:5304</code>)</td><td><code>.cc-assistant-popover</code></td></tr><tr><td>Header (<code>4218:5305</code>, ChatHeader instance)</td><td><code>.cc-assistant-popover__header</code></td></tr><tr><td>Header left container</td><td><code>.cc-assistant-popover__brand</code></td></tr><tr><td>AI badge (32px, sparkles)</td><td><code>.cc-assistant-popover__badge</code> + <code>&lt;i data-lucide=&quot;sparkles&quot;&gt;</code></td></tr><tr><td>&quot;Affino Assistant&quot; title</td><td><code>.cc-assistant-popover__title</code></td></tr><tr><td>Close button</td><td><code>.cc-assistant-popover__close</code> (<code>btn btn--tertiary btn--sm btn--icon</code>, <code>x</code>)</td></tr><tr><td>Body frame (<code>4218:5306</code>)</td><td><code>.cc-assistant-popover__body</code></td></tr><tr><td>Intro (<code>4218:5307</code>/<code>4218:5309</code>)</td><td><code>.cc-assistant-popover__intro</code> &gt; 2× <code>&lt;p&gt;</code></td></tr><tr><td>Launch button (<code>4218:5337</code>)</td><td><code>.cc-assistant-popover__launch</code> (<code>btn btn--primary</code>, <code>arrow-right</code>)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma variable</th><th>CSS token</th><th>Role</th></tr></thead><tbody><tr><td><code>--ai-surface-primary</code></td><td><code>--ai-surface-primary</code></td><td>Card background</td></tr><tr><td><code>--ai-radius-lg</code> (16)</td><td><code>--ai-radius-lg</code></td><td>Card radius</td></tr><tr><td><code>--ai-size-6</code> (320)</td><td><code>--ai-size-6</code></td><td>Card width</td></tr><tr><td><code>light/shadow-md</code></td><td><code>--ai-shadow-md</code></td><td>Card drop shadow (offset 0,2 / blur 10)</td></tr><tr><td><code>--ai-border-secondary</code></td><td><code>--ai-border-secondary</code></td><td>Header bottom divider (1px)</td></tr><tr><td><code>--ai-spacing-4</code> (12)</td><td><code>--ai-spacing-4</code></td><td>Header padding</td></tr><tr><td><code>--ai-spacing-5</code> (16)</td><td><code>--ai-spacing-5</code></td><td>Header gap; body padding + gap</td></tr><tr><td><code>--ai-spacing-3</code> (8)</td><td><code>--ai-spacing-3</code></td><td>Brand gap; intro paragraph gap (see Gaps)</td></tr><tr><td><code>--ai-spacing-7</code> (32)</td><td><code>--ai-spacing-7</code></td><td>AI badge size</td></tr><tr><td><code>--ai-radius-md</code> (8)</td><td><code>--ai-radius-md</code></td><td>AI badge radius</td></tr><tr><td><code>--cc-actions-menu-secondary-bg</code></td><td><code>--cc-actions-menu-secondary-bg</code></td><td>AI badge background</td></tr><tr><td><code>--cc-actions-menu-icon</code></td><td><code>--cc-actions-menu-icon</code></td><td>AI badge sparkles colour</td></tr><tr><td><code>--ai-icon-size-sm</code> (16)</td><td><code>--ai-icon-size-sm</code></td><td>Badge icon size</td></tr><tr><td><code>--ai-font-fixed-xs</code> (14) + <code>--ai-font-semibold</code> + <code>--ai-leading-md</code> (24)</td><td>same</td><td>Title type</td></tr><tr><td><code>--ai-text-primary</code></td><td><code>--ai-text-primary</code></td><td>Title colour</td></tr><tr><td><code>--ai-font-fixed-xs</code> (14) + <code>--ai-font-regular</code></td><td>same</td><td>Intro type — <strong>user override</strong> to fixed-xs (Figma bound <code>--ai-font-fluid-sm</code>)</td></tr><tr><td><code>--ai-text-secondary</code></td><td><code>--ai-text-secondary</code></td><td>Intro colour</td></tr><tr><td><code>--ai-btn-primary-*</code></td><td>(Button component)</td><td>Launch button</td></tr><tr><td><code>--ai-btn-tertiary-*</code></td><td>(Button component)</td><td>Close button</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><ul><li><strong>Intro paragraph gap = 7px in Figma</strong> (<code>mb-[7px]</code>), no <code>--ai-spacing-*</code> token equals 7. <strong>Resolved (user, 2026-06-03):</strong> use <code>--ai-spacing-3</code> (8px), the nearest token.</li><li>Intro <code>line-height: 1.5</code> — Figma <code>leading-[1.5]</code> unitless ratio (not a px leading token); kept as the ratio, same approach as IconNavigation labels.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Standalone, not the AiAssistant.</strong> Figma&#39;s component is <code>AiAssistant / Type=Pop Over</code>, but built here as its own pattern per user direction.</li><li><strong><code>--cc-actions-menu-icon</code> value mismatch:</strong> Figma reports <code>#335562</code> for this token; the project&#39;s <code>tokens-cc.css</code> currently has <code>#667f89</code>. Used the <strong>token</strong> (source of truth in code); the value drift is a designer-sync matter, not hardcoded around.</li><li>Badge glyph is a standard <code>sparkles</code> (Lucide), not a bespoke brand SVG. Sized via <code>.cc-assistant-popover__badge [data-lucide]</code> (Lucide swaps the <code>&lt;i&gt;</code> for <code>&lt;svg&gt;</code>, so the size selector targets <code>[data-lucide]</code>, the project convention — not <code>i</code>).</li><li><strong>Close button bg (scoped override):</strong> in the CC brand <code>--ai-btn-tertiary-bg</code> is a visible grey (<code>#e5e9eb</code>), so <code>.cc-assistant-popover__close</code> forces <code>background-color: transparent</code> by default (user, 2026-06-03). Hover/active still come from <code>btn--tertiary</code>.</li><li>Body has a <strong>hidden</strong> &quot;Title&quot; text node in Figma (<code>4218:5308</code>) — only the subtext renders.</li><li>Lucide icons: <code>sparkles</code> (badge), <code>x</code> (close), <code>arrow-right</code> (Launch trailing).</li><li><strong>Dismiss wired (<code>AssistantPopover.js</code>, 2026-06-03):</strong> clicking <code>.cc-assistant-popover__close</code> removes the pop-over from the DOM (document-delegated). The rest of the behaviour (positioning, when it appears, re-show) is still to be specced separately.</li><li>Requires <code>data-brand=&quot;cc&quot;</code> on an ancestor for the <code>--cc-*</code> badge tokens.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><code>Button</code> (<code>src/components/Button/</code>) — Launch (<code>btn btn--primary</code>) + close (<code>btn btn--tertiary btn--sm btn--icon</code>).</li><li><code>AssistantPopover.js</code> — close-to-dismiss behaviour.</li><li>Lucide icons.</li></ul>',17)])])}const u=t(c,[["render",r]]);export{h as __pageData,u as default};
